// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

import org.eclipse.rdf4j.sail.lmdb.TxnManager.Txn;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Tests for {@link TripleStore#planRootSplitKeys}: interpolated, snapped-to-actual-key split points whose half-open
 * ranges tile a pattern's key range with no duplicates and no gaps.
 */
public class TripleStoreRangePartitionTest {

	@TempDir
	File dataDir;

	private TripleStore tripleStore;

	@BeforeEach
	public void setUp() throws Exception {
		tripleStore = new TripleStore(dataDir, new LmdbStoreConfig("spoc,posc"), null);
	}

	private void store(long subj, long pred, long obj, long context, boolean explicit) throws Exception {
		tripleStore.storeTriple(subj, pred, obj, context, explicit);
	}

	/** Scans every partition implied by the split keys and asserts the union equals the unpartitioned scan. */
	private void assertTiling(Txn txn, long subj, long pred, long obj, long context, boolean explicit,
			List<byte[]> splits) throws Exception {
		String indexName = tripleStore.getIndexName(subj, pred, obj, context);
		List<long[]> partitioned = new ArrayList<>();
		byte[] low = null;
		for (int i = 0; i <= splits.size(); i++) {
			byte[] high = i < splits.size() ? splits.get(i) : null;
			try (RecordIterator iterator = tripleStore.getTriplesRange(txn, subj, pred, obj, context, explicit,
					new LmdbKeyRange(low, high, indexName))) {
				long[] quad;
				while ((quad = iterator.next()) != null) {
					partitioned.add(quad.clone());
				}
			}
			low = high;
		}
		List<long[]> full = new ArrayList<>();
		try (RecordIterator iterator = tripleStore.getTriples(txn, subj, pred, obj, context, explicit)) {
			long[] quad;
			while ((quad = iterator.next()) != null) {
				full.add(quad.clone());
			}
		}
		assertThat(partitioned).hasSameSizeAs(full);
		for (int i = 0; i < full.size(); i++) {
			assertThat(partitioned.get(i)).containsExactly(full.get(i));
		}
	}

	@Test
	public void uniformIdsYieldBalancedSortedSplits() throws Exception {
		tripleStore.startTransaction();
		for (long subj = 1000; subj < 2000; subj++) {
			store(subj, 10, 5000 + subj, 1, true);
		}
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			List<byte[]> splits = tripleStore.planRootSplitKeys(txn, -1, 10, -1, -1, true, 8);
			assertThat(splits).hasSizeBetween(4, 7); // interpolation may collapse a few, never exceeds target-1
			for (int i = 1; i < splits.size(); i++) {
				assertThat(Arrays.compareUnsigned(splits.get(i - 1), splits.get(i))).isLessThan(0);
			}
			assertTiling(txn, -1, 10, -1, -1, true, splits);
		}
	}

	@Test
	public void clusteredIdsStillTile() throws Exception {
		tripleStore.startTransaction();
		// heavy skew: 900 keys in a tight cluster, 100 spread far away
		for (long i = 0; i < 900; i++) {
			store(70_000 + i, 10, 100_000 + i, 1, true);
		}
		for (long i = 0; i < 100; i++) {
			store(9_000_000_000L + i * 1_000_000L, 10, 100 + i, 1, true);
		}
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			List<byte[]> splits = tripleStore.planRootSplitKeys(txn, -1, 10, -1, -1, true, 8);
			// skewed interpolation may produce few usable splits, but whatever survives must tile exactly
			assertTiling(txn, -1, 10, -1, -1, true, splits);
		}
	}

	@Test
	public void fewDistinctKeysCollapseToRefusal() throws Exception {
		tripleStore.startTransaction();
		store(100, 10, 1100, 1, true);
		store(101, 10, 1101, 1, true);
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			List<byte[]> splits = tripleStore.planRootSplitKeys(txn, -1, 10, -1, -1, true, 8);
			// with two keys the only admissible split is the last key itself; tiling must hold either way
			assertThat(splits.size()).isLessThanOrEqualTo(1);
			assertTiling(txn, -1, 10, -1, -1, true, splits);
		}
	}

	@Test
	public void emptyRangeYieldsNoSplits() throws Exception {
		tripleStore.startTransaction();
		store(100, 10, 1100, 1, true);
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			assertThat(tripleStore.planRootSplitKeys(txn, -1, 99, -1, -1, true, 8)).isEmpty();
		}
	}

	@Test
	public void inferredDbIsPartitionedIndependently() throws Exception {
		tripleStore.startTransaction();
		for (long subj = 100; subj < 400; subj++) {
			store(subj, 10, 1000 + subj, 1, false); // inferred
		}
		store(50, 10, 900, 1, true); // one explicit quad only
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			List<byte[]> inferredSplits = tripleStore.planRootSplitKeys(txn, -1, 10, -1, -1, false, 4);
			assertTiling(txn, -1, 10, -1, -1, false, inferredSplits);
			// explicit db has a single key: nothing to split, tiling trivially holds
			List<byte[]> explicitSplits = tripleStore.planRootSplitKeys(txn, -1, 10, -1, -1, true, 4);
			assertThat(explicitSplits).isEmpty();
			assertTiling(txn, -1, 10, -1, -1, true, explicitSplits);
		}
	}

	@Test
	public void splitsRespectBoundPrefix() throws Exception {
		tripleStore.startTransaction();
		for (long subj = 1000; subj < 1500; subj++) {
			store(subj, 10, 5000 + subj, 1, true);
			store(subj, 20, 7000 + subj, 1, true); // neighboring predicate must never leak into partitions
		}
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			List<byte[]> splits = tripleStore.planRootSplitKeys(txn, -1, 10, -1, -1, true, 4);
			assertThat(splits).isNotEmpty();
			assertTiling(txn, -1, 10, -1, -1, true, splits);
		}
	}
}
